mapper.select:
SELECT COUNT(*) FROM product_items pi JOIN product_brands pb ON pi.brand_id = pb.brand_id WHERE pi.status = 'active'
AND pb.brand_name = #{brand}
AND (REPLACE(pi.name, ' ', '') LIKE CONCAT('%', REPLACE(#{searchKeyword}, ' ', ''), '%') OR REPLACE(pb.brand_name, ' ', '') LIKE CONCAT('%', REPLACE(#{searchKeyword}, ' ', ''), '%'))

SELECT pi.product_id, pi.category_id, pi.brand_id, pb.brand_name, pi.name, pi.description, pi.status, pi.image_url, pi.price, pi.weight, pi.kcal, pi.protein, pi.sodium, pi.sugar, pi.saturated_fat, pi.caffeine, pi.created_at, pi.updated_at, pi.informer_user_id, u.login_id AS informer_nickname FROM product_items pi JOIN product_brands pb ON pi.brand_id = pb.brand_id LEFT JOIN users u ON pi.informer_user_id = u.user_id WHERE pi.status = 'active'
AND pb.brand_name = #{brand}
AND (REPLACE(pi.name, ' ', '') LIKE CONCAT('%', REPLACE(#{searchKeyword}, ' ', ''), '%') OR REPLACE(pb.brand_name, ' ', '') LIKE CONCAT('%', REPLACE(#{searchKeyword}, ' ', ''), '%'))
ORDER BY pi.name ASC ORDER BY pi.price ASC ORDER BY pi.price DESC ORDER BY pi.kcal ASC ORDER BY pi.kcal DESC ORDER BY pi.protein ASC ORDER BY pi.protein DESC
ORDER BY ( SELECT COUNT(g.gram_id) FROM grams g WHERE g.product_id = pi.product_id AND g.created_at >= DATE_SUB(NOW(), INTERVAL 7 DAY) ) DESC, pi.product_id ASC
LIMIT #{size} OFFSET #{offset}
